#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int main(void) {
    srand(time(NULL));
    int numbers[5], guessed[5] = {0}, score = 0;

    // Generate 5 unique random numbers between 1 and 10
    for (int i = 0; i < 5; i++) {
        int num;
        do {
            num = rand() % 10 + 1;
        } while (num == 0 || guessed[num - 1]);
        numbers[i] = num;
        guessed[num - 1] = 1;
    }

    // Game loop
    for (int i = 0; i < 5; i++) {
        printf("Numbers: ");
        for (int j = 0; j < 5; j++) {
            if (guessed[j]) {
                printf("%d ", numbers[j]);
            } else {
                printf("* ");
            }
        }
        printf("\nPick position (1-5): ");
        int pos;
        scanf("%d", &pos);

        printf("Guess (E for even, O for odd): ");
        char guess;
        scanf(" %c", &guess);

        if ((numbers[pos - 1] % 2 == 0 && guess == 'E') || 
            (numbers[pos - 1] % 2 != 0 && guess == 'O')) {
            printf("Correct!\n");
            score += 5;
        } else {
            printf("Incorrect.\n");
        }

        guessed[pos - 1] = 1;
    }

    // Display final score
    printf("Final Score: %d\n", score);

    return 0;
}

