#include <stdio.h>
#include <stdlib.h>

int main() {
    int numbers[5], guessPos, guessType, score = 0;
    char guessStr[2];

    // Generate 5 unique random numbers between 1 and 10
    for (int i = 0; i < 5; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && is_member(numbers[i], numbers, i));
    }

    // Hide numbers initially
    for (int i = 0; i < 5; i++) {
        printf("* ");
    }
    printf("\n");

    // Game loop
    for (int i = 0; i < 5; i++) {
        printf("Pick position (0-4): ");
        scanf("%d", &guessPos);
        printf("Guess even or odd (E/O): ");
        scanf("%s", guessStr);

        if (guessPos >= 0 && guessPos < 5) {
            guessType = (guessStr[0] == 'E') ? 0 : 1;

            if ((numbers[guessPos] % 2 == 0 && guessType == 0) || 
                (numbers[guessPos] % 2 != 0 && guessType == 1)) {
                printf("Correct! You win 5 points.\n");
                score += 5;
            } else {
                printf("Incorrect!\n");
            }

            // Reveal the number
            printf("Number at position %d: %d\n", guessPos, numbers[guessPos]);
        } else {
            printf("Invalid position. Try again.\n");
        }
    }

    // Display final score
    printf("Final score: %d\n", score);

    return 0;
}

// Helper function to check if a number is already in the array
int is_member(int num, int arr[], int size) {
    for (int i = 0; i < size; i++) {
        if (arr[i] == num) {
            return 1;
        }
    }
    return 0;
}
